   321→            </div>
   322→          </div>
   323→        )}
   324→      </aside>
   325→
   326→      {/* Main content */}
   327→      <main
   328→        className={cn(
   329→          'min-h-screen transition-all duration-300 p-8 pt-20',
   330→          sidebarOpen ? 'ml-64' : 'ml-20'
