   368→
   369→          {currentView === 'quiz' && <LazyQuizView />}
   370→
   371→          {currentView === 'flashcards' && <LazyFlashcardsView />}
   372→
   373→          {currentView === 'mindmaps' && <LazyMindmapsView />}
   374→
   375→          {currentView === 'summaries' && <LazySummariesView />}
   376→
   377→          {currentView === 'homework' && <LazyHomeworkHelpView />}
