interface UIState {
  sidebarOpen: boolean;
  settingsOpen: boolean;
  currentView: 'maestri' | 'chat' | 'voice' | 'quiz' | 'flashcards' | 'homework' | 'progress';
  // Focus Mode - fullscreen tool view
  focusMode: boolean;
  focusTool: ToolState | null;
  focusToolType: ToolType | null;
  focusMaestroId: string | null;
  // Actions
  toggleSidebar: () => void;
  setSidebarOpen: (open: boolean) => void;
  toggleSettings: () => void;
  setCurrentView: (view: UIState['currentView']) => void;
  // Focus Mode Actions
  enterFocusMode: (toolType: ToolType, maestroId?: string) => void;
  setFocusTool: (tool: ToolState | null) => void;
  exitFocusMode: () => void;
}

export const useUIStore = create<UIState>((set) => ({
  sidebarOpen: true,
  settingsOpen: false,
  currentView: 'maestri',
  focusMode: false,
  focusTool: null,
  focusToolType: null,
  focusMaestroId: null,
  toggleSidebar: () => set((state) => ({ sidebarOpen: !state.sidebarOpen })),
  setSidebarOpen: (sidebarOpen) => set({ sidebarOpen }),
  toggleSettings: () => set((state) => ({ settingsOpen: !state.settingsOpen })),
  setCurrentView: (currentView) => set({ currentView }),
  enterFocusMode: (toolType, maestroId) => set({
    focusMode: true,
    focusToolType: toolType,
    focusMaestroId: maestroId || null,
    focusTool: null, // Will be set when tool is created
  }),
  setFocusTool: (tool) => set({ focusTool: tool }),
  exitFocusMode: () => set({
    focusMode: false,
    focusTool: null,
    focusToolType: null,
    focusMaestroId: null,
  }),
}));

// === SYNC HOOK ===

export async function initializeStores() {
  // Ensure user exists (creates cookie if needed)
  await fetch('/api/user');

  // Load data from server
  await Promise.all([
    useSettingsStore.getState().loadFromServer(),
    useProgressStore.getState().loadFromServer(),
    useConversationStore.getState().loadFromServer(),
    useLearningsStore.getState().loadFromServer(),
  ]);

