                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                      <DropdownMenuItem onClick={() => handleExport(selectedMindmap, 'json')}>
                        <FileJson className="w-4 h-4 mr-2" />
                        JSON
