                <Button onClick={handleCreateMindmap} disabled={!newMapTitle.trim() || !newMapTopics.some(t => t.name.trim())}>
                  <Save className="w-4 h-4 mr-2" />
                  Crea Mappa
                </Button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

