  search: 'melissa',
  webcam: 'melissa',
  pdf: 'melissa',
  homework: 'melissa',
};

// Map subjects to maestros (for future use)
const _SUBJECT_TO_MAESTRO: Record<string, string> = {
  mathematics: 'euclid',
  math: 'euclid',
  matematica: 'euclid',
  history: 'herodotus',
  storia: 'herodotus',
  italian: 'manzoni',
