content.content:
     1→'use client';
     2→
     3→/**
     4→ * FocusToolLayout - Fullscreen layout for working with tools
     5→ *
     6→ * Layout:
     7→ * - Left (1/3): Chat with maestro/coach
     8→ * - Right (2/3): Tool panel (mindmap, quiz, etc.)
     9→ * - Header: Minimal with exit button
    10→ * - ESC to exit
    11→ */
    12→
    13→import { useEffect, useCallback, useState, useRef } from 'react';
    14→import { motion, AnimatePresence } from 'framer-motion';
    15→import { X, Loader2, Send, Mic, MicOff, Phone, PhoneOff, Volume2 } from 'lucide-react';
    16→import { Button } from '@/components/ui/button';
    17→import { ToolPanel } from './tool-panel';
    18→import { useUIStore, useSettingsStore } from '@/lib/stores/app-store';
    19→import { getMaestroById } from '@/data/maestri';
    20→import { getSupportTeacherById } from '@/data/support-teachers';
    21→import { useVoiceSession } from '@/lib/hooks/use-voice-session';
    22→import { logger } from '@/lib/logger';
    23→import type { ToolType } from '@/types/tools';
    24→import type { MaestroFull } from '@/data/maestri';
    25→import type { SupportTeacher } from '@/types';
    26→import { cn } from '@/lib/utils';
    27→
    28→// Map tool types to suggested maestros (for future use)
    29→const _TOOL_TO_MAESTRO: Record<ToolType, string> = {
    30→  mindmap: 'melissa', // Coach for general organization
    31→  quiz: 'melissa',
    32→  flashcard: 'melissa',
    33→  summary: 'melissa',
    34→  demo: 'ada', // Ada for demos/coding
    35→  diagram: 'euclid', // Euclid for diagrams
    36→  timeline: 'herodotus', // Herodotus for timelines
    37→  formula: 'euclid',
    38→  chart: 'euclid',
    39→  search: 'melissa',
    40→  webcam: 'melissa',
    41→  pdf: 'melissa',
    42→  homework: 'melissa',
    43→};
    44→
    45→// Map subjects to maestros (for future use)
    46→const _SUBJECT_TO_MAESTRO: Record<string, string> = {
    47→  mathematics: 'euclid',
    48→  math: 'euclid',
    49→  matematica: 'euclid',
    50→  history: 'herodotus',
    51→  storia: 'herodotus',
    52→  italian: 'manzoni',
    53→  italiano: 'manzoni',
    54→  english: 'shakespeare',
    55→  inglese: 'shakespeare',
    56→  physics: 'feynman',
    57→  fisica: 'feynman',
    58→  chemistry: 'curie',
    59→  chimica: 'curie',
    60→  biology: 'darwin',
    61→  biologia: 'darwin',
    62→  scienze: 'darwin',
    63→  geography: 'humboldt',
    64→  geografia: 'humboldt',
    65→  art: 'davinci',
    66→  arte: 'davinci',
    67→  music: 'mozart',
    68→  musica: 'mozart',
    69→  philosophy: 'socrates',
    70→  filosofia: 'socrates',
    71→  economics: 'smith',
    72→  economia: 'smith',
    73→  civics: 'cicero',
    74→  educazione_civica: 'cicero',
    75→  pe: 'hippocrates',
    76→  educazione_fisica: 'hippocrates',
    77→  coding: 'ada',
    78→  informatica: 'ada',
    79→  storytelling: 'chris',
    80→};
    81→
    82→interface Message {
    83→  id: string;
    84→  role: 'user' | 'assistant';
    85→  content: string;
    86→  timestamp: Date;
    87→}
    88→
    89→// Map function names to tool types
    90→const FUNCTION_NAME_TO_TOOL_TYPE: Record<string, ToolType> = {
    91→  create_mindmap: 'mindmap',
    92→  create_quiz: 'quiz',
    93→  create_demo: 'demo',
    94→  web_search: 'search',
    95→  create_flashcards: 'flashcard',
    96→  create_diagram: 'diagram',
    97→  create_timeline: 'timeline',
    98→  create_summary: 'summary',
    99→  open_student_summary: 'summary',
   100→};
   101→
   102→export function FocusToolLayout() {
   103→  const { focusMode, focusToolType, focusMaestroId, focusInteractionMode, focusTool, setFocusTool, exitFocusMode } = useUIStore();
   104→  const { studentProfile } = useSettingsStore();
   105→
   106→  const [messages, setMessages] = useState<Message[]>([]);
   107→  const [input, setInput] = useState('');
   108→  const [isLoading, setIsLoading] = useState(false);
   109→  const [isVoiceActive, setIsVoiceActive] = useState(false);
   110→  const [connectionInfo, setConnectionInfo] = useState<{ provider: 'azure'; proxyPort: number; configured: boolean } | null>(null);
   111→  const [configError, setConfigError] = useState<string | null>(null);
   112→  const messagesEndRef = useRef<HTMLDivElement>(null);
   113→  const inputRef = useRef<HTMLInputElement>(null);
   114→  const lastTranscriptIdRef = useRef<string | null>(null);
   115→
   116→  // Determine which maestro/coach to use
   117→  const getMaestroOrCoach = useCallback((): MaestroFull | SupportTeacher | null => {
   118→    // If specific maestro requested
   119→    if (focusMaestroId) {
   120→      const maestro = getMaestroById(focusMaestroId);
   121→      if (maestro) return maestro;
   122→
   123→      // Check if it's a coach
   124→      const coach = getSupportTeacherById(focusMaestroId as 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij');
   125→      if (coach) return coach;
   126→    }
   127→
   128→    // Default to coach based on preference or tool type
   129→    const preferredCoach = studentProfile?.preferredCoach || 'melissa';
   130→    const coach = getSupportTeacherById(preferredCoach);
   131→    if (coach) return coach;
   132→
   133→    return null;
   134→  }, [focusMaestroId, studentProfile?.preferredCoach]);
   135→
   136→  const character = getMaestroOrCoach();
   137→
   138→  // Helper to get display properties from either MaestroFull or SupportTeacher
   139→  const getCharacterProps = (char: MaestroFull | SupportTeacher | null) => {
   140→    if (!char) return null;
   141→    // MaestroFull has displayName, SupportTeacher has name
   142→    const isMaestro = 'displayName' in char;
   143→    return {
   144→      name: isMaestro ? (char as MaestroFull).displayName : char.name,
   145→      avatar: char.avatar || '/avatars/default.jpg',
   146→      color: char.color,
   147→      systemPrompt: char.systemPrompt,
   148→      greeting: char.greeting,
   149→    };
   150→  };
   151→
   152→  const characterProps = getCharacterProps(character);
   153→
   154→  // Voice session hook - must be after character is defined
   155→  const {
   156→    isConnected: voiceConnected,
   157→    isListening,
   158→    isSpeaking,
   159→    isMuted,
   160→    inputLevel,
   161→    connectionState,
   162→    connect: voiceConnect,
   163→    disconnect: voiceDisconnect,
   164→    toggleMute,
   165→    sessionId: voiceSessionId,
   166→  } = useVoiceSession({
   167→    onError: (error) => {
   168→      const message = error instanceof Error ? error.message : String(error);
   169→      logger.error('Voice session error in focus mode', { message });
   170→      setConfigError(message || 'Errore di connessione vocale');
   171→    },
   172→    onTranscript: (role, text) => {
   173→      // Add voice transcripts to messages
   174→      const transcriptId = `voice-${role}-${Date.now()}`;
   175→
   176→      // Avoid duplicate transcripts
   177→      if (lastTranscriptIdRef.current === text.substring(0, 50)) {
   178→        return;
   179→      }
   180→      lastTranscriptIdRef.current = text.substring(0, 50);
   181→
   182→      setMessages(prev => [...prev, {
   183→        id: transcriptId,
   184→        role,
   185→        content: text,
   186→        timestamp: new Date(),
   187→      }]);
   188→    },
   189→  });
   190→
   191→  // Fetch voice connection info on mount
   192→  useEffect(() => {
   193→    async function fetchConnectionInfo() {
   194→      try {
   195→        const response = await fetch('/api/realtime/token');
   196→        const data = await response.json();
   197→        if (data.error) {
   198→          logger.error('Voice API error', { error: data.error });
   199→          setConfigError(data.message || 'Servizio vocale non configurato');
   200→          return;
   201→        }
   202→        setConnectionInfo(data);
   203→      } catch (error) {
   204→        logger.error('Failed to get voice connection info', { error: String(error) });
   205→        setConfigError('Impossibile connettersi al servizio vocale');
   206→      }
   207→    }
   208→    if (focusMode) {
   209→      fetchConnectionInfo();
   210→    }
   211→  }, [focusMode]);
   212→
   213→  // Auto-start voice if interaction mode is 'voice'
   214→  useEffect(() => {
   215→    if (focusMode && focusInteractionMode === 'voice' && connectionInfo && !isVoiceActive) {
   216→      setIsVoiceActive(true);
   217→    }
   218→  }, [focusMode, focusInteractionMode, connectionInfo, isVoiceActive]);
   219→
   220→  // Connect to voice when activated
   221→  useEffect(() => {
   222→    if (!isVoiceActive || !connectionInfo || connectionState !== 'idle' || !character) return;
   223→
   224→    const startVoice = async () => {
   225→      setConfigError(null);
   226→      try {
   227→        // Create a maestro-like object for the voice session
   228→        const maestroForVoice = {
   229→          id: character.id,
   230→          name: characterProps?.name || 'Coach',
   231→          systemPrompt: characterProps?.systemPrompt || '',
   232→          avatar: characterProps?.avatar || '/avatars/default.jpg',
   233→          greeting: characterProps?.greeting || '',
   234→          subject: 'general',
   235→          specialty: '',
   236→          color: characterProps?.color || '#3b82f6',
   237→        };
   238→        await voiceConnect(maestroForVoice, connectionInfo);
   239→      } catch (error) {
   240→        logger.error('Voice connection failed', { error: String(error) });
   241→        if (error instanceof DOMException && error.name === 'NotAllowedError') {
   242→          setConfigError('Microfono non autorizzato. Abilita il microfono nelle impostazioni del browser.');
   243→        } else {
   244→          setConfigError('Errore di connessione vocale');
   245→        }
   246→        setIsVoiceActive(false);
   247→      }
   248→    };
   249→
   250→    startVoice();
   251→  }, [isVoiceActive, connectionInfo, connectionState, character, characterProps, voiceConnect]);
   252→
   253→  // Handle voice toggle
   254→  const handleVoiceToggle = useCallback(() => {
   255→    if (isVoiceActive) {
   256→      voiceDisconnect();
   257→      setIsVoiceActive(false);
   258→    } else {
   259→      setIsVoiceActive(true);
   260→    }
   261→  }, [isVoiceActive, voiceDisconnect]);
   262→
   263→  // ESC key handler
   264→  useEffect(() => {
   265→    const handleKeyDown = (e: KeyboardEvent) => {
   266→      if (e.key === 'Escape' && focusMode) {
   267→        exitFocusMode();
   268→      }
   269→    };
   270→
   271→    window.addEventListener('keydown', handleKeyDown);
   272→    return () => window.removeEventListener('keydown', handleKeyDown);
   273→  }, [focusMode, exitFocusMode]);
   274→
   275→  // Auto-scroll messages
   276→  useEffect(() => {
   277→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   278→  }, [messages]);
   279→
   280→  // Focus input when mode activates
   281→  useEffect(() => {
   282→    if (focusMode) {
   283→      inputRef.current?.focus();
   284→    }
   285→  }, [focusMode]);
   286→
   287→  // Initial greeting message
   288→  useEffect(() => {
   289→    if (focusMode && characterProps && messages.length === 0) {
   290→      const toolNames: Record<ToolType, string> = {
   291→        mindmap: 'mappa mentale',
   292→        quiz: 'quiz',
   293→        flashcard: 'flashcard',
   294→        summary: 'riassunto',
   295→        demo: 'demo interattiva',
   296→        diagram: 'diagramma',
   297→        timeline: 'linea del tempo',
   298→        formula: 'formula',
   299→        chart: 'grafico',
   300→        search: 'ricerca',
   301→        webcam: 'foto',
   302→        pdf: 'PDF',
   303→        homework: 'compiti',
   304→      };
   305→
   306→      const toolName = focusToolType ? toolNames[focusToolType] : 'strumento';
   307→
   308→      setMessages([{
   309→        id: 'greeting',
   310→        role: 'assistant',
   311→        content: `Ciao! Sono ${characterProps.name}. Creiamo insieme una ${toolName}! Di che argomento vuoi parlare?`,
   312→        timestamp: new Date(),
   313→      }]);
   314→    }
   315→  }, [focusMode, characterProps, focusToolType, messages.length]);
   316→
   317→  // Handle sending message
   318→  const handleSend = useCallback(async () => {
   319→    if (!input.trim() || isLoading || !character || !characterProps) return;
   320→
   321→    const userMessage = input.trim();
   322→    setInput('');
   323→    setIsLoading(true);
   324→
   325→    const newUserMessage: Message = {
   326→      id: `user-${Date.now()}`,
   327→      role: 'user',
   328→      content: userMessage,
   329→      timestamp: new Date(),
   330→    };
   331→
   332→    setMessages(prev => [...prev, newUserMessage]);
   333→
   334→    try {
   335→      const response = await fetch('/api/chat', {
   336→        method: 'POST',
   337→        headers: { 'Content-Type': 'application/json' },
   338→        body: JSON.stringify({
   339→          messages: [
   340→            ...messages.map(m => ({ role: m.role, content: m.content })),
   341→            { role: 'user', content: userMessage },
   342→          ],
   343→          systemPrompt: characterProps.systemPrompt,
   344→          maestroId: character.id,
   345→          enableTools: true,
   346→          requestedTool: focusToolType,
   347→        }),
   348→      });
   349→
   350→      if (!response.ok) throw new Error('Failed to send message');
   351→
   352→      const data = await response.json();
   353→
   354→      const assistantMessage: Message = {
   355→        id: `assistant-${Date.now()}`,
   356→        role: 'assistant',
   357→        content: data.content || '',
   358→        timestamp: new Date(),
   359→      };
   360→
   361→      if (data.content) {
   362→        setMessages(prev => [...prev, assistantMessage]);
   363→      }
   364→
   365→      // Handle tool calls if any
   366→      if (data.toolCalls && data.toolCalls.length > 0) {
   367→        const toolCall = data.toolCalls[0];
   368→        const toolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || focusToolType || 'mindmap';
   369→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   370→
   371→        setFocusTool({
   372→          id: toolCall.id || `tool-${Date.now()}`,
   373→          type: toolType,
   374→          status: 'completed',
   375→          progress: 1,
   376→          content: toolContent,
   377→          createdAt: new Date(),
   378→        });
   379→      }
   380→    } catch (error) {
   381→      logger.error('Chat error in focus mode', { error });
   382→      setMessages(prev => [...prev, {
   383→        id: `error-${Date.now()}`,
   384→        role: 'assistant',
   385→        content: 'Mi dispiace, c\'è stato un errore. Riprova!',
   386→        timestamp: new Date(),
   387→      }]);
   388→    } finally {
   389→      setIsLoading(false);
   390→    }
   391→  }, [input, isLoading, character, characterProps, messages, focusToolType, setFocusTool]);
   392→
   393→  const handleKeyPress = (e: React.KeyboardEvent) => {
   394→    if (e.key === 'Enter' && !e.shiftKey) {
   395→      e.preventDefault();
   396→      handleSend();
   397→    }
   398→  };
   399→
   400→  if (!focusMode) return null;
   401→
   402→  return (
   403→    <AnimatePresence>
   404→      <motion.div
   405→        initial={{ opacity: 0 }}
   406→        animate={{ opacity: 1 }}
   407→        exit={{ opacity: 0 }}
   408→        className="fixed inset-0 z-50 bg-white dark:bg-slate-950"
   409→      >
   410→        {/* Header */}
   411→        <header className="h-14 flex items-center justify-between px-4 border-b border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
   412→          <div className="flex items-center gap-3">
   413→            {characterProps && (
   414→              <>
   415→                <div
   416→                  className="w-8 h-8 rounded-full bg-cover bg-center"
   417→                  style={{ backgroundImage: `url(${characterProps.avatar})` }}
   418→                />
   419→                <span className="font-semibold text-slate-900 dark:text-white">
